import{_ as a,c as o,o as s,aA as r}from"./chunks/framework.CLrzXryn.js";const i="/RadialBasisFunctions.jl/previews/PR125/assets/hessian_phs_matched.BJgtyY1F.png",n="/RadialBasisFunctions.jl/previews/PR125/assets/hessian_phs_polydeg_sweep.KhfcZ9WG.png",t="/RadialBasisFunctions.jl/previews/PR125/assets/hessian_imq_gaussian_polydeg.TK33msdy.png",c="/RadialBasisFunctions.jl/previews/PR125/assets/jacobian_phs_matched.BNBLL53O.png",l="/RadialBasisFunctions.jl/previews/PR125/assets/jacobian_phs_polydeg_sweep.Dvt0W16_.png",h="/RadialBasisFunctions.jl/previews/PR125/assets/jacobian_imq_gaussian_polydeg.Biu7LVHC.png",d="/RadialBasisFunctions.jl/previews/PR125/assets/divergence_phs_matched.CVeT_ROj.png",p="/RadialBasisFunctions.jl/previews/PR125/assets/divergence_phs_polydeg_sweep.BcuHhE8z.png",u="/RadialBasisFunctions.jl/previews/PR125/assets/divergence_imq_gaussian_polydeg.BUUWZZvl.png",m="/RadialBasisFunctions.jl/previews/PR125/assets/curl2d_phs_matched.VvsOsQDV.png",g="/RadialBasisFunctions.jl/previews/PR125/assets/curl2d_phs_polydeg_sweep.DhmxeLCx.png",_="/RadialBasisFunctions.jl/previews/PR125/assets/curl2d_imq_gaussian_polydeg.B0_5e6DC.png",q=JSON.parse('{"title":"Vector &amp; Higher-Rank Operators","description":"","frontmatter":{},"headers":[],"relativePath":"guides/convergence/vector-operators.md","filePath":"guides/convergence/vector-operators.md","lastUpdated":null}'),H={name:"guides/convergence/vector-operators.md"};function P(v,e,b,f,x,w){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="Vector-and-Higher-Rank-Operators" tabindex="-1">Vector &amp; Higher-Rank Operators <a class="header-anchor" href="#Vector-and-Higher-Rank-Operators" aria-label="Permalink to &quot;Vector &amp;amp; Higher-Rank Operators {#Vector-and-Higher-Rank-Operators}&quot;">​</a></h1><p>Convergence for operators that produce tensor output or act on vector fields: <code>hessian</code>, <code>jacobian</code>, <code>divergence</code>, <code>curl</code>. The test vector field is <code>u(x) = [sin(πx₁) + 0.5cos(2πx₂), exp(x₁x₂)]</code> on <code>[0,1]²</code> with all components having nonzero partials.</p><h2 id="Hessian" tabindex="-1">Hessian <a class="header-anchor" href="#Hessian" aria-label="Permalink to &quot;Hessian {#Hessian}&quot;">​</a></h2><p>The Hessian assembles second partials <code>∂²u/∂xᵢ∂xⱼ</code> into an <code>N × D × D</code> tensor. Error is reported as a Frobenius NRMSE. Because one of the four entries is a mixed partial, the Hessian inherits the mixed-partial caveat — the non-converging combos are the same as for the <a href="/RadialBasisFunctions.jl/previews/PR125/guides/convergence/scalar-operators#mixed-partial-xxj">mixed partial</a> operator.</p><div class="warning custom-block"><p class="custom-block-title">Excluded combinations</p><p>Same set as mixed partial: <code>PHS1/p=1</code>, <code>PHS3/p=1</code>, <code>PHS3/p=2</code>, <code>PHS5/p=2</code>, <code>IMQ/p=0</code>, <code>IMQ/p=2</code>, <code>Gaussian/p=0</code>, <code>Gaussian/p=2</code> are omitted. <strong>Use PHS5/p=3 or higher for the full Hessian.</strong></p></div><h3 id="Which-PHS-order?" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?}&quot;">​</a></h3><p><img src="'+i+'" alt=""></p><p>Only PHS5/p=3 and PHS7/p=4 converge. They reach <code>O(h²)</code> and <code>O(h⁴)</code> respectively.</p><h3 id="How-much-polynomial-degree?" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?}&quot;">​</a></h3><p><img src="'+n+'" alt=""></p><h3 id="Do-IMQ-/-Gaussian-help?" tabindex="-1">Do IMQ / Gaussian help? <a class="header-anchor" href="#Do-IMQ-/-Gaussian-help?" aria-label="Permalink to &quot;Do IMQ / Gaussian help? {#Do-IMQ-/-Gaussian-help?}&quot;">​</a></h3><p><img src="'+t+'" alt=""></p><h2 id="Jacobian" tabindex="-1">Jacobian <a class="header-anchor" href="#Jacobian" aria-label="Permalink to &quot;Jacobian {#Jacobian}&quot;">​</a></h2><p>The Jacobian of a vector field is an <code>N × Dᵢₙ × Dₒᵤₜ</code> tensor of first partials — no second derivatives, no mixed-partial issue. Convergence matches the gradient cleanly.</p><h3 id="Which-PHS-order?-2" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-2" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-2}&quot;">​</a></h3><p><img src="'+c+'" alt=""></p><h3 id="How-much-polynomial-degree?-2" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-2" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-2}&quot;">​</a></h3><p><img src="'+l+'" alt=""></p><h3 id="Do-IMQ-/-Gaussian-help?-2" tabindex="-1">Do IMQ / Gaussian help? <a class="header-anchor" href="#Do-IMQ-/-Gaussian-help?-2" aria-label="Permalink to &quot;Do IMQ / Gaussian help? {#Do-IMQ-/-Gaussian-help?-2}&quot;">​</a></h3><p><img src="'+h+'" alt=""></p><h2 id="Divergence-·" tabindex="-1">Divergence (∇·) <a class="header-anchor" href="#Divergence-·" aria-label="Permalink to &quot;Divergence (∇·) {#Divergence-·}&quot;">​</a></h2><p><code>∇·u = ∂u₁/∂x₁ + ∂u₂/∂x₂</code> — a sum of first partials. Convergence rates match the gradient; all PHS orders at matched poly_deg are well-behaved.</p><h3 id="Which-PHS-order?-3" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-3" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-3}&quot;">​</a></h3><p><img src="'+d+'" alt=""></p><h3 id="How-much-polynomial-degree?-3" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-3" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-3}&quot;">​</a></h3><p><img src="'+p+'" alt=""></p><h3 id="Do-IMQ-/-Gaussian-help?-3" tabindex="-1">Do IMQ / Gaussian help? <a class="header-anchor" href="#Do-IMQ-/-Gaussian-help?-3" aria-label="Permalink to &quot;Do IMQ / Gaussian help? {#Do-IMQ-/-Gaussian-help?-3}&quot;">​</a></h3><p><img src="'+u+'" alt=""></p><h2 id="Curl-,-2D" tabindex="-1">Curl (∇×, 2D) <a class="header-anchor" href="#Curl-,-2D" aria-label="Permalink to &quot;Curl (∇×, 2D) {#Curl-,-2D}&quot;">​</a></h2><p>In 2D, <code>∇×u = ∂u₂/∂x₁ − ∂u₁/∂x₂</code> (the scalar z-component). Like divergence, this is a first-derivative operator and follows the same convergence profile.</p><h3 id="Which-PHS-order?-4" tabindex="-1">Which PHS order? <a class="header-anchor" href="#Which-PHS-order?-4" aria-label="Permalink to &quot;Which PHS order? {#Which-PHS-order?-4}&quot;">​</a></h3><p><img src="'+m+'" alt=""></p><h3 id="How-much-polynomial-degree?-4" tabindex="-1">How much polynomial degree? <a class="header-anchor" href="#How-much-polynomial-degree?-4" aria-label="Permalink to &quot;How much polynomial degree? {#How-much-polynomial-degree?-4}&quot;">​</a></h3><p><img src="'+g+'" alt=""></p><h3 id="Do-IMQ-/-Gaussian-help?-4" tabindex="-1">Do IMQ / Gaussian help? <a class="header-anchor" href="#Do-IMQ-/-Gaussian-help?-4" aria-label="Permalink to &quot;Do IMQ / Gaussian help? {#Do-IMQ-/-Gaussian-help?-4}&quot;">​</a></h3><p><img src="'+_+'" alt=""></p>',36)])])}const y=a(H,[["render",P]]);export{q as __pageData,y as default};
